// // This SR latch will set Q to 0 when S=1 and R=0, and Qn to 1. It will reset Q to 1 and Qn to 0 when S=0 and R=1. When both S=0 and R=0, it will toggle Q and Qn. An invalid state of S=R=1 will keep Q and Qn unchanged.
module sr_latch (
    input wire S,
    input wire R,
    output reg Q,
    output reg Qn
);
    always @ (S or R) begin
        if (S && ~R) begin
            Q <= 1;
            Qn <= 0;
        end else if (~S && R) begin
            Q <= 0;
            Qn <= 1;
        end else if (~S && ~R) begin
            // retain previous state
            Q <= Q;
            Qn <= Qn;
        end else begin
            // invalid state, hold previous state
            Q <= Q;
            Qn <= Qn;
        end
    end
endmodule
